export * from "./input-otp";
export * as InputOTP from "./namespace";
export * from "./styles";

"use client";

import { OTPInput, OTPInputContext } from "input-otp";
import { MinusIcon } from "lucide-react";

import { useContext } from "react";
import { InputOTPStyles } from "./styles";

export type InputOTPRootProps = React.ComponentProps<typeof OTPInput> & {
  containerClassName?: string;
};

export function InputOTPRoot({
  className,
  containerClassName,
  ...props
}: InputOTPRootProps) {
  return (
    <OTPInput
      className={InputOTPStyles.Root({ className })}
      containerClassName={InputOTPStyles.Container({
        class: containerClassName,
      })}
      data-slot="input-otp"
      {...props}
    />
  );
}

export interface InputOTPGroupProps extends React.ComponentProps<"div"> {}

export function InputOTPGroup({ className, ...props }: InputOTPGroupProps) {
  return (
    <div
      className={InputOTPStyles.Group({ className })}
      data-slot="input-otp-group"
      {...props}
    />
  );
}

export interface InputOTPSlotProps extends React.ComponentProps<"div"> {
  index: number;
}

export function InputOTPSlot({
  index,
  className,
  ...props
}: InputOTPSlotProps) {
  const inputOTPContext = useContext(OTPInputContext);
  const { char, hasFakeCaret, isActive } = inputOTPContext?.slots[index] ?? {};

  return (
    <div
      className={InputOTPStyles.Slot({ className })}
      data-active={isActive}
      data-slot="input-otp-slot"
      {...props}
    >
      {char}
      {hasFakeCaret && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div className="h-4 w-px animate-caret-blink bg-foreground duration-1000" />
        </div>
      )}
    </div>
  );
}

export interface InputOTPSeparatorProps extends React.ComponentProps<"div"> {}

export function InputOTPSeparator({ ...props }: InputOTPSeparatorProps) {
  return (
    <div
      data-slot="input-otp-separator"
      // biome-ignore lint/a11y/useAriaPropsForRole: This is a decorative separator
      role="separator"
      tabIndex={-1}
      {...props}
    >
      <MinusIcon />
    </div>
  );
}

import { cva } from "~/registry/lib/cva";

export const InputOTPStyles = {
  Container: cva({
    base: ["flex items-center gap-2 has-disabled:opacity-50"],
  }),
  Group: cva({
    base: ["flex items-center"],
  }),
  Root: cva({
    base: ["disabled:cursor-not-allowed"],
  }),
  Slot: cva({
    base: [
      "relative flex size-9 items-center justify-center border-input border-y border-r text-sm shadow-xs outline-none transition-all",
      "first:rounded-l-md first:border-l",
      "last:rounded-r-md",
      "aria-invalid:border-destructive",
      "data-[active=true]:z-10 data-[active=true]:border-ring data-[active=true]:ring-[3px] data-[active=true]:ring-ring/50",
      "data-[active=true]:aria-invalid:border-destructive data-[active=true]:aria-invalid:ring-destructive/20",
      "dark:bg-input/30 dark:data-[active=true]:aria-invalid:ring-destructive/40",
    ],
  }),
};

export {
  InputOTPGroup as Group,
  InputOTPRoot as Root,
  InputOTPSeparator as Separator,
  InputOTPSlot as Slot,
} from "./input-otp";
